#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[51];
        scanf("%s", s);
        int n = strlen(s);
        int robots[n];
        int ranges[n][2];
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] != '.') {
                robots[count] = i;
                ranges[count][0] = i - (s[i] - '0');
                ranges[count][1] = i + (s[i] - '0');
                count++;
            }
        }
        int graph[count][count];
        for (int i = 0; i < count; i++) {
            for (int j = 0; j < count; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < count; i++) {
            for (int j = 0; j < count; j++) {
                if (i != j) {
                    if (ranges[i][0] <= ranges[j][1] && ranges[j][0] <= ranges[i][1]) {
                        graph[i][j] = 1;
                    }
                }
            }
        }
        int visited[count];
        for (int i = 0; i < count; i++) {
            visited[i] = 0;
        }
        int cycle = 0;
        for (int i = 0; i < count; i++) {
            if (!visited[i]) {
                if (dfs(graph, visited, i, -1)) {
                    cycle = 1;
                    break;
                }
            }
        }
        if (cycle) {
            printf("unsafe\n");
        } else {
            printf("safe\n");
        }
    }
    return 0;
}

int dfs(int graph[][51], int visited[], int node, int parent) {
    visited[node] = 1;
    for (int i = 0; i < 51; i++) {
        if (graph[node][i] && !visited[i]) {
            if (dfs(graph, visited, i, node)) {
                return 1;
            }
        } else if (graph[node][i] && i == parent) {
            return 1;
        }
    }
    return 0;
}

